console.log("[WalmartSplit] Background service worker started");chrome.action.onClicked.addListener(e=>{if(console.log("[WalmartSplit] Icon clicked, tab URL:",e.url),!!e.id){if(!e.url?.includes("walmart.com")){chrome.tabs.create({url:chrome.runtime.getURL("index.html")});return}chrome.tabs.sendMessage(e.id,{action:"extract_receipt"},()=>{if(chrome.runtime.lastError){console.log("[WalmartSplit] Content script not ready, injecting now...",chrome.runtime.lastError.message);const t=chrome.runtime.getManifest().content_scripts?.[0]?.js;t&&e.id&&chrome.scripting.executeScript({target:{tabId:e.id},files:t}).then(()=>{console.log("[WalmartSplit] Content script injected. Sending message..."),setTimeout(()=>{chrome.tabs.sendMessage(e.id,{action:"extract_receipt"})},100)}).catch(r=>{console.error("[WalmartSplit] Failed to inject content script:",r)})}})}});
